public class HDG_SysMultiThreadSendAlertBatch extends RunBaseBatch
{
    str userId;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        userId
    #endmacro

}

Method.Source:
public str parmUserId(str _userId = userId)
{
    userId = _userId;
    return userId;
}

public server static HDG_SysMultiThreadSendAlertBatch construct()
{
    return new HDG_SysMultiThreadSendAlertBatch();
}

public ClassDescription caption()
{
    return "Send alert when the batch is finished";
}

public boolean unpack(container _packedClass)
{
    int version = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version, #CurrentList] = _packedClass;
            break;

        default:
            return false;
    }

    return true;
}

public static void main(Args _args)
{
    HDG_SysMultiThreadSendAlertBatch batch = HDG_SysMultiThreadSendAlertBatch::construct();

    if (batch.prompt())
    {
        batch.runOperation();
    }
}

public void run()
{
    str                     messageText;

    messageText = "Multi-thread processing has been completed.";

    // Set up the notification
    SystemNotificationDataContract notification = new SystemNotificationDataContract();
    notification.Users().value(1, userId);
    notification.Title("Multi-thread finished");
    notification.RuleId('HDG_SysMultiThreadSendAlertBatch');
    notification.Message(messageText);
    notification.ExpirationDateTime(DateTimeUtil::addHours(DateTimeUtil::utcNow(), 48));

    SystemNotificationsManager::AddSystemNotification(notification);
}
